def most_common_word(s):
    if not s:
        return ''

    words = s.lower().split()
    word_counts = {}

    for word in words:
        if word in word_counts:
            word_counts[word] += 1
        else:
            word_counts[word] = 1

    return max(word_counts, key=lambda k: (-word_counts[k], k))
